define("mod_booking/sync_rule_modal",["core_form/modalform"],(function(ModalForm){return{init:function(selector,cmid,optionid,title){const element=document.querySelector(selector);element&&element.addEventListener("click",(function(e){e.preventDefault();const modalForm=new ModalForm({formClass:"mod_booking\\form\\sync_rule_form",args:{cmid:cmid,optionid:optionid},modalConfig:{title:title||"Add sync rule"},returnFocus:element});modalForm.addEventListener(modalForm.events.FORM_SUBMITTED,(function(){window.location.reload()})),modalForm.show()}))}}}));